dashboard.definition:
{
    "title": "Agentic Usage · Sessions",
    "description": "",
    "inputs": {
        "input_time": {
            "options": {
                "defaultValue": "-7d@h,now",
                "token": "tr"
            },
            "title": "Time Range (user list only — panels use fixed live windows)",
            "type": "input.timerange"
        },
        "input_user": {
            "dataSources": {
                "primary": "ds_userlist"
            },
            "options": {
                "defaultValue": "All",
                "items": [
                    {
                        "label": "All Users",
                        "value": "All"
                    }
                ],
                "token": "selected_user"
            },
            "title": "User",
            "type": "input.dropdown"
        },
        "input_service": {
            "options": {
                "defaultValue": "All",
                "items": [
                    {
                        "label": "All Harnesses",
                        "value": "All"
                    },
                    {
                        "label": "Claude Code",
                        "value": "claude-code"
                    },
                    {
                        "label": "Claude Desktop",
                        "value": "claude-code-desktop"
                    },
                    {
                        "label": "Cowork",
                        "value": "cowork"
                    },
                    {
                        "label": "Gemini CLI",
                        "value": "gemini-cli"
                    },
                    {
                        "label": "Codex",
                        "value": "codex"
                    }
                ],
                "token": "selected_service"
            },
            "title": "Harness",
            "type": "input.dropdown"
        },
        "input_theme": {
            "options": {
                "defaultValue": "#0a0c10",
                "items": [
                    {
                        "label": "Dark",
                        "value": "#0a0c10"
                    },
                    {
                        "label": "Light",
                        "value": "#f4f6f8"
                    }
                ],
                "token": "theme"
            },
            "title": "Theme",
            "type": "input.dropdown"
        }
    },
    "defaults": {
        "dataSources": {}
    },
    "visualizations": {
        "viz_sess_ticker": {
            "type": "agentic_usage.cu_ticker",
            "options": {
                "agentic_usage.cu_ticker.theme": "$theme$",
                "agentic_usage.cu_ticker.title": "SESSIONS",
                "agentic_usage.cu_ticker.kindField": "kind",
                "agentic_usage.cu_ticker.textField": "text",
                "agentic_usage.cu_ticker.scrollSpeed": "medium",
                "agentic_usage.cu_ticker.maxItems": "30",
                "agentic_usage.cu_ticker.accentColor": "#28b6a4",
                "agentic_usage.cu_ticker.liveColor": "#f2643d"
            },
            "dataSources": {
                "primary": "ds_sess_ticker"
            }
        },
        "viz_sess_active": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "ACTIVE SESSIONS",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "true",
                "agentic_usage.cu_kpi.accentColor": "#28b6a4"
            },
            "dataSources": {
                "primary": "ds_sess_kpi_active"
            }
        },
        "viz_sess_users": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "ACTIVE USERS",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#3aa6c2"
            },
            "dataSources": {
                "primary": "ds_sess_kpi_users"
            }
        },
        "viz_sess_today": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "SESSIONS TODAY",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#e6b24a"
            },
            "dataSources": {
                "primary": "ds_sess_kpi_today"
            }
        },
        "viz_sess_avglen": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "AVG SESSION LENGTH",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#52b487"
            },
            "dataSources": {
                "primary": "ds_sess_kpi_avglen"
            }
        },
        "viz_sess_burn": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "EST. BURN RATE · CLAUDE ONLY",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.unit": "/hr",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#f2643d"
            },
            "dataSources": {
                "primary": "ds_sess_kpi_burn"
            }
        },
        "viz_sess_board": {
            "type": "agentic_usage.cu_sessions",
            "options": {
                "agentic_usage.cu_sessions.theme": "$theme$",
                "agentic_usage.cu_sessions.title": "Active Sessions",
                "agentic_usage.cu_sessions.subtitle": "live · 30m window",
                "agentic_usage.cu_sessions.activeThresholdSec": "120",
                "agentic_usage.cu_sessions.ctxWarnPct": "60",
                "agentic_usage.cu_sessions.ctxHighPct": "85",
                "agentic_usage.cu_sessions.accentColor": "#28b6a4",
                "agentic_usage.cu_sessions.maxRows": "50"
            },
            "dataSources": {
                "primary": "ds_sess_board"
            }
        },
        "viz_sess_top": {
            "type": "agentic_usage.cu_bars",
            "options": {
                "agentic_usage.cu_bars.theme": "$theme$",
                "agentic_usage.cu_bars.title": "Top Sessions Today",
                "agentic_usage.cu_bars.subtitle": "by tokens",
                "agentic_usage.cu_bars.labelField": "Session",
                "agentic_usage.cu_bars.valueField": "Tokens (M)",
                "agentic_usage.cu_bars.valueUnit": "M",
                "agentic_usage.cu_bars.secondaryField": "Detail",
                "agentic_usage.cu_bars.secondarySuffix": "",
                "agentic_usage.cu_bars.barColor": "#28b6a4",
                "agentic_usage.cu_bars.maxRows": "0"
            },
            "dataSources": {
                "primary": "ds_sess_top"
            }
        },
        "viz_sess_feed": {
            "type": "agentic_usage.cu_feed",
            "options": {
                "agentic_usage.cu_feed.theme": "$theme$",
                "agentic_usage.cu_feed.title": "Session Events",
                "agentic_usage.cu_feed.subtitle": "errors · compactions · agents",
                "agentic_usage.cu_feed.timeField": "Time",
                "agentic_usage.cu_feed.userField": "User",
                "agentic_usage.cu_feed.projectField": "Session",
                "agentic_usage.cu_feed.textField": "Event",
                "agentic_usage.cu_feed.badgeField": "Badge",
                "agentic_usage.cu_feed.detailField": "Detail",
                "agentic_usage.cu_feed.accentColor": "#28b6a4",
                "agentic_usage.cu_feed.maxRows": "100"
            },
            "dataSources": {
                "primary": "ds_sess_feed"
            }
        }
    },
    "dataSources": {
        "ds_userlist": {
            "type": "ds.search",
            "options": {
                "query": "| mstats fillnull_value=\"__missing__\" count(_value) AS points WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.token.relationship\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where isnotnull(identity) | stats count BY identity | eval value=identity, label=identity | sort label | fields label value",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_sess_ticker": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.user_prompt\",\"agentic.api_error\",\"gen_ai.client.operation.exception\",\"agentic.api_retries_exhausted\",\"agentic.compaction\",\"agentic.session_started\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | eval user=mvindex(split(coalesce(identity,\"Unknown\"),\"@\"),0) | eval user=if(match(user,\"^[0-9a-f][0-9a-f-]{15,}$\"), substr(user,1,8).\"…\", user) | eval kind=case('event.name'==\"agentic.user_prompt\",\"PROMPT\",'event.name'==\"agentic.compaction\",\"COMPACT\",'event.name'==\"agentic.session_started\",\"START\",1=1,\"ERROR\") | eval text=case('event.name'==\"agentic.user_prompt\", user.\" sent a prompt\", 'event.name'==\"agentic.compaction\", user.\" compacted context\", 'event.name'==\"agentic.session_started\", user.\" started a session\", 'event.name'==\"agentic.api_retries_exhausted\", user.\" exhausted API retries\", 1=1, user.\" hit \".substr(coalesce('error.type','exception.type',\"an API error\"),1,60)) | sort - _time | head 40 | table _time kind user text | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting live activity\", kind=\"\"]",
                "queryParameters": {
                    "earliest": "-60m",
                    "latest": "now"
                }
            }
        },
        "ds_sess_kpi_active": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.api_request\",\"agentic.user_prompt\",\"agentic.tool_result\",\"agentic.tool_execution\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats dc(\"gen_ai.conversation.id\") AS value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "-30m",
                    "latest": "now"
                }
            }
        },
        "ds_sess_kpi_users": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.api_request\",\"agentic.user_prompt\",\"agentic.tool_result\",\"agentic.tool_execution\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats dc(identity) AS value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "-30m",
                    "latest": "now"
                }
            }
        },
        "ds_sess_kpi_today": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS sessions WHERE `agentic_metrics` metric_name=\"agentic.session.started\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats sum(sessions) AS total | where isnotnull(total) | eval value=round(total) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "@d",
                    "latest": "now"
                }
            }
        },
        "ds_sess_kpi_avglen": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.api_request\",\"agentic.user_prompt\",\"agentic.tool_result\",\"agentic.tool_execution\",\"agentic.session_started\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats min(_time) AS st max(_time) AS en BY \"gen_ai.conversation.id\" | where en>st | stats avg(eval(en-st)) AS avg_s | eval m=round(avg_s/60) | eval value=if(m>=60, floor(m/60).\"h \".(m%60).\"m\", m.\"m\") | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=\"0m\"]",
                "queryParameters": {
                    "earliest": "@d",
                    "latest": "now"
                }
            }
        },
        "ds_sess_kpi_burn": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS cost WHERE `agentic_metrics` metric_name=\"agentic.cost.estimated\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats sum(cost) AS c | eval value=case(\"$selected_service$\" IN (\"gemini-cli\",\"codex\"), \"n/a\", isnotnull(c), urldecode(\"%24\").tostring(round(c*4,2)), true(), null()) | where isnotnull(value) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=urldecode(\"%24\").\"0\"]",
                "queryParameters": {
                    "earliest": "-15m",
                    "latest": "now"
                }
            }
        },
        "ds_sess_board": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.api_request\",\"agentic.user_prompt\",\"agentic.tool_result\",\"agentic.tool_execution\",\"agentic.api_error\",\"gen_ai.client.operation.exception\",\"agentic.api_retries_exhausted\",\"agentic.session_started\",\"agentic.subagent_completed\",\"agentic.compaction\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | stats min(_time) AS started, max(_time) AS last_seen, latest(identity) AS user, latest(\"service.name\") AS service, latest(\"gen_ai.provider.name\") AS provider, sum(eval(if('event.name'==\"agentic.api_request\", coalesce('agentic.cost.estimated_usd',0), 0))) AS cost, sum(eval(if('event.name'==\"agentic.api_request\", coalesce('gen_ai.usage.input_tokens',0)+coalesce('gen_ai.usage.output_tokens',0), 0))) AS tokens, count(eval('event.name'==\"agentic.user_prompt\")) AS prompts, count(eval('event.name' IN (\"agentic.tool_result\",\"agentic.tool_execution\"))) AS tools, count(eval('event.name' IN (\"agentic.api_error\",\"gen_ai.client.operation.exception\",\"agentic.api_retries_exhausted\"))) AS errors, count(eval('event.name'==\"agentic.subagent_completed\")) AS subagents, count(eval('event.name'==\"agentic.compaction\")) AS compactions, latest(\"agentic.model.context_window\") AS model_window, latest(eval(if('event.name'==\"agentic.api_request\" AND 'agentic.query.source'==\"repl_main_thread\", 'gen_ai.usage.input_tokens', null()))) AS ctx_main, latest(eval(if('event.name'==\"agentic.api_request\" AND (isnull('agentic.query.source') OR NOT like('agentic.query.source',\"agent%\")), 'gen_ai.usage.input_tokens', null()))) AS ctx_any, latest(eval(if('event.name'==\"agentic.api_request\" AND 'agentic.query.source'==\"repl_main_thread\", 'gen_ai.request.model', null()))) AS model_main, latest(eval(if('event.name'==\"agentic.api_request\" AND (isnull('agentic.query.source') OR NOT like('agentic.query.source',\"agent%\")), 'gen_ai.request.model', null()))) AS model_any, latest(eval(if('event.name' IN (\"agentic.tool_result\",\"agentic.tool_execution\"), 'gen_ai.tool.name', null()))) AS last_tool BY \"gen_ai.conversation.id\" | where last_seen >= relative_time(now(), \"-30m\") AND (tokens>0 OR prompts>0 OR tools>0 OR errors>0) | eval cost=if(cost>0, cost, null()) | eval model=coalesce(model_main, model_any, \"unknown\"), ctx_tokens=coalesce(ctx_main, ctx_any) | lookup agentic_model_context model_pattern AS model OUTPUT context_window | eval ctx_window=coalesce(model_window, context_window, 200000) | eval model=replace(model, \"^claude-\", \"\") | eval ctx_pct=if(isnotnull(ctx_tokens), min(round(ctx_tokens/ctx_window*100,1), 100), 0) | eval user=mvindex(split(coalesce(user,\"Unknown\"),\"@\"),0) | eval user=if(match(user,\"^[0-9a-f][0-9a-f-]{15,}$\"), substr(user,1,8).\"…\", user) | rename \"gen_ai.conversation.id\" AS \"session.id\" | sort - last_seen | table session.id user service provider model started last_seen cost tokens prompts tools errors subagents compactions ctx_tokens ctx_pct last_tool | appendpipe [| stats count | where count=0 | eval _status=\"No active sessions\", user=\"\"]",
                "queryParameters": {
                    "earliest": "-24h@m",
                    "latest": "now"
                }
            }
        },
        "ds_sess_top": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name=\"agentic.api_request\" | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | eval u=mvindex(split(coalesce(identity,\"Unknown\"),\"@\"),0) | eval u=if(match(u,\"^[0-9a-f][0-9a-f-]{15,}$\"), substr(u,1,8).\"…\", u) | stats min(_time) AS st, max(_time) AS en, latest(u) AS user, sum(eval(coalesce('gen_ai.usage.input_tokens',0)+coalesce('gen_ai.usage.output_tokens',0))) AS tokens, sum(\"agentic.cost.estimated_usd\") AS cost BY \"gen_ai.conversation.id\" | where tokens>0 | sort - tokens | head 12 | eval mins=round((en-st)/60), dur=if(mins>=60, floor(mins/60).\"h \".(mins%60).\"m\", mins.\"m\") | eval Session=user.\" · \".substr('gen_ai.conversation.id',1,8) | eval TokensM=round(tokens/1000000,1) | eval Detail=dur.if(coalesce(cost,0)>0, \" · \".urldecode(\"%24\").tostring(round(cost,2)), \"\") | rename TokensM AS \"Tokens (M)\" | table Session \"Tokens (M)\" Detail | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", Session=\"\"]",
                "queryParameters": {
                    "earliest": "@d",
                    "latest": "now"
                }
            }
        },
        "ds_sess_feed": {
            "type": "ds.search",
            "options": {
                "refresh": "30s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.compaction\",\"agentic.api_error\",\"gen_ai.client.operation.exception\",\"agentic.api_retries_exhausted\",\"agentic.permission_mode_changed\",\"agentic.subagent_completed\") | eval identity=coalesce('user.email','user.id') | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | eval User=mvindex(split(coalesce(identity,\"Unknown\"),\"@\"),0) | eval User=if(match(User,\"^[0-9a-f][0-9a-f-]{15,}$\"), substr(User,1,8).\"…\", User) | eval Time=strftime(_time,\"%H:%M:%S\") | eval Session=substr('gen_ai.conversation.id',1,8) | eval Badge=case('event.name' IN (\"agentic.api_error\",\"gen_ai.client.operation.exception\"),\"ERROR\",'event.name'==\"agentic.api_retries_exhausted\",\"FAILED\",'event.name'==\"agentic.compaction\",\"COMPACT\",'event.name'==\"agentic.permission_mode_changed\",\"MODE\",1=1,\"AGENT\") | eval Event=case('event.name' IN (\"agentic.api_error\",\"gen_ai.client.operation.exception\"), \"API error · \".substr(coalesce('error.type','exception.type',\"unknown\"),1,120), 'event.name'==\"agentic.api_retries_exhausted\", \"API retries exhausted\", 'event.name'==\"agentic.compaction\", if(isnotnull('agentic.compaction.tokens_before') OR isnotnull('agentic.compaction.tokens_after'), \"context compaction · \".coalesce(tostring('agentic.compaction.tokens_before'),\"?\").\" → \".coalesce(tostring('agentic.compaction.tokens_after'),\"?\").\" tokens\", \"context compaction\"), 'event.name'==\"agentic.permission_mode_changed\", \"permission mode changed\", 1=1, \"subagent \".coalesce('gen_ai.agent.name','agentic.agent.type',\"agent\").\" completed\".if(isnotnull('agentic.operation.duration_ms'),\" · \".tostring('agentic.operation.duration_ms').\" ms\",\"\")) | eval Detail=\"Session: \".coalesce('gen_ai.conversation.id',\"—\").\" || Model: \".coalesce('gen_ai.request.model',\"—\").\" || Error type: \".coalesce('error.type','exception.type',\"—\").\" || Duration: \".coalesce(tostring('agentic.operation.duration_ms'),\"—\").\" ms\" | eval Detail=if(Badge IN (\"ERROR\",\"FAILED\"), Detail, \"\") | sort - _time | head 100 | table Time User Session Event Badge Detail | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", Time=\"\"]",
                "queryParameters": {
                    "earliest": "-4h",
                    "latest": "now"
                }
            }
        }
    },
    "layout": {
        "type": "absolute",
        "options": {
            "display": "auto-scale",
            "width": 1480,
            "height": 1220,
            "backgroundColor": "$theme$",
            "showTitleAndDescription": false
        },
        "globalInputs": [
            "input_time",
            "input_user",
            "input_service",
            "input_theme"
        ],
        "structure": [
            {
                "item": "viz_sess_ticker",
                "type": "block",
                "position": {
                    "x": 10,
                    "y": 10,
                    "w": 1460,
                    "h": 56
